parameters.jsCode:
const analysis = JSON.parse($json.output);

return [
  {
    json: analysis
  }
];

const analysis = $json;
const rows = $('Extract from File').all();

function col(i) {
    return analysis.required_columns[i];
}

switch (analysis.operation) {

    // ============================
    // SUM OF (COLUMN1 × COLUMN2)
    // ============================
    case "sum_product": {

        const col1 = col(0);
        const col2 = col(1);

        let total = 0;

        for (const r of rows) {
            total +=
                Number(r.json[col1] || 0) *
                Number(r.json[col2] || 0);
        }

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: total
            }
        }];
    }

    // ============================
    // AVERAGE
    // ============================
    case "average": {

        const column = col(0);

        const values = rows
            .map(r => Number(r.json[column]))
            .filter(v => !isNaN(v));

        const avg =
            values.reduce((a, b) => a + b, 0) /
            (values.length || 1);

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: avg
            }
        }];
    }

    // ============================
    // SUM
    // ============================
    case "sum": {

        const column = col(0);

        const total = rows.reduce((sum, r) => {
            return sum + Number(r.json[column] || 0);
        }, 0);

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: total
            }
        }];
    }

    // ============================
    // COUNT
    // ============================
    case "count": {

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: rows.length
            }
        }];
    }

    // ============================
    // MIN
    // ============================
    case "min": {

        const column = col(0);

        const values = rows
            .map(r => Number(r.json[column]))
            .filter(v => !isNaN(v));

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: Math.min(...values)
            }
        }];
    }

    // ============================
    // MAX
    // ============================
    case "max": {

        const column = col(0);

        const values = rows
            .map(r => Number(r.json[column]))
            .filter(v => !isNaN(v));

        return [{
            json: {
                type: "kpi",
                title: analysis.title,
                value: Math.max(...values)
            }
        }];
    }

    // ============================
    // UNKNOWN
    // ============================
    default:

        return [{
            json: {
                skipped: true,
                operation: analysis.operation
            }
        }];
}

