parameters.jsCode:
const charts = $('Code in JavaScript').first().json.charts;
const urls = $('Generate QuickChart URLs').all();

let urlIndex = 0;

for (const chart of charts) {

    // الـ KPI لا يحتاج صورة
    if (chart.type === 'kpi') {
        continue;
    }
  if (chart.type === 'table') {
        continue;
    }

    // إذا لا يوجد رابط نتجاهله
    if (!urls[urlIndex]) {
        console.log(`Missing URL for ${chart.title}`);
        continue;
    }

    chart.image = urls[urlIndex].json.url;

    urlIndex++;
}

return [
{
    json: {
        charts
    }
}
];

const supported = [
  'bar',
  'line',
  'pie',
  'doughnut',
  'histogram',
  'scatter',
  'radar',

  'polarArea'
];

return items.filter(item =>
  supported.includes(item.json.type)
);

const rows = $input.all().map(i => i.json);

if (rows.length === 0) {
  return [{
    json: {
      profiling: {
        totalRows: 0,
        totalColumns: 0,
        columns: [],
        missingValues: {},
        duplicateRows: 0,
        dataQuality: 100
      }
    }
  }];
}

const columns = Object.keys(rows[0]);

const profile = [];
const missingValues = {};

function isMissing(v) {
  return v === null || v === undefined || v === "";
}

function percentile(sorted, p) {
  if (sorted.length === 0) return null;

  const index = (sorted.length - 1) * p;
  const lower = Math.floor(index);
  const upper = Math.ceil(index);

  if (lower === upper) return sorted[lower];

  return sorted[lower] + (sorted[upper] - sorted[lower]) * (index - lower);
}

for (const col of columns) {
  const values = rows.map(r => r[col]);

  const missing = values.filter(isMissing).length;
  missingValues[col] = missing;

  const nonMissingValues = values.filter(v => !isMissing(v));

  const numeric =
    nonMissingValues.length > 0 &&
    nonMissingValues.every(v => !isNaN(Number(v)));

  if (numeric) {
    const nums = nonMissingValues.map(Number);
    const sorted = [...nums].sort((a, b) => a - b);

    const min = Math.min(...nums);
    const max = Math.max(...nums);

    const mean = nums.reduce((a, b) => a + b, 0) / nums.length;

    const variance =
      nums.reduce((sum, value) => sum + Math.pow(value - mean, 2), 0) / nums.length;

    const std = Math.sqrt(variance);

    const median = percentile(sorted, 0.5);
    const q1 = percentile(sorted, 0.25);
    const q3 = percentile(sorted, 0.75);
    const iqr = q3 - q1;

    profile.push({
      name: col,
      type: "Numeric",
      min: Number(min.toFixed(2)),
      max: Number(max.toFixed(2)),
      average: Number(mean.toFixed(2)),
      median: Number(median.toFixed(2)),
      q1: Number(q1.toFixed(2)),
      q3: Number(q3.toFixed(2)),
      iqr: Number(iqr.toFixed(2)),
      std: Number(std.toFixed(2)),
      missing
    });
  } else {
    profile.push({
      name: col,
      type: "Categorical",
      uniqueValues: new Set(nonMissingValues).size,
      missing
    });
  }
}

const duplicateRows =
  rows.length - new Set(rows.map(r => JSON.stringify(r))).size;

const totalMissing =
  Object.values(missingValues).reduce((a, b) => a + b, 0);

const denominator = rows.length * columns.length;

const quality = denominator === 0
  ? 100
  : Math.max(0, 100 - ((totalMissing + duplicateRows) / denominator) * 100);

return [{
  json: {
    profiling: {
      totalRows: rows.length,
      totalColumns: columns.length,
      duplicateRows,
      missingValues,
      dataQuality: Number(quality.toFixed(1)),
      columns: profile
    }
  }
}];

return [{
  json: {

    metadata: $('Code (metadata + data)').first().json.metadata,

    profiling: $('Data Profiling').first().json.profiling,

    analyses: $('Code (Parse JSON)').first().json.analyses,

    charts: $('Attach Chart URL').first().json.charts,

    rows: $('Extract from File').all().map(i => i.json),

    columns: Object.keys($('Extract from File').first().json)

  }
}];

const data = $input.first().json;

function jsonForHtml(value) {
    return JSON.stringify(value ?? {})
        .replace(/</g, "\\u003c")
        .replace(/>/g, "\\u003e")
        .replace(/&/g, "\\u0026")
        .replace(/\u2028/g, "\\u2028")
        .replace(/\u2029/g, "\\u2029");
}

