.stat{
    padding:9px;
    background:var(--panel-2);
    border:1px solid var(--border);
    border-radius:8px;
    min-width:0;
}
.stat-label{
    color:var(--muted);
    font-size:11px;
    font-weight:850;
    text-transform:uppercase;
    letter-spacing:.04em;
}
.stat-value{
    margin-top:4px;
    font-weight:950;
    overflow-wrap:anywhere;
}
.chart-card{
    min-height:434px;
    display:flex;
    flex-direction:column;
    overflow:hidden;
}
.chart-header{
    padding:14px 16px 10px;
    display:flex;
    align-items:flex-start;
    justify-content:space-between;
    gap:12px;
    border-bottom:1px solid var(--border);
}
.chart-title{
    margin:0;
    font-size:14px;
    line-height:1.25;
    font-weight:950;
    overflow-wrap:anywhere;
}
.chart-subtitle{
    margin-top:4px;
    color:var(--muted);
    font-size:12px;
    overflow-wrap:anywhere;
}
.chart-actions{display:flex;gap:8px;flex:0 0 auto}
.icon-btn{
    width:34px;
    height:34px;
    border:1px solid var(--border);
    background:var(--panel);
    color:var(--text);
    border-radius:8px;
    display:grid;
    place-items:center;
}
.icon-btn:hover{background:var(--panel-3)}
.chart{
    width:100%;
    height:360px;
    min-height:300px;
}
.table-card{overflow:hidden}
.table-shell{
    width:100%;
    overflow:auto;
    max-height:680px;
}
table{
    width:100%;
    min-width:760px;
    border-collapse:separate;
    border-spacing:0;
}
thead th{
    position:sticky;
    top:0;
    z-index:2;
    background:var(--panel-2);
    color:var(--muted);
    text-align:left;
    font-size:11px;
    font-weight:950;
    text-transform:uppercase;
    letter-spacing:.05em;
    border-bottom:1px solid var(--border);
    padding:11px 12px;
    white-space:nowrap;
    user-select:none;
}
thead th.sortable{cursor:pointer}
tbody td{
    border-bottom:1px solid var(--border);
    padding:11px 12px;
    vertical-align:top;
    max-width:340px;
    white-space:nowrap;
    overflow:hidden;
    text-overflow:ellipsis;
}
tbody tr:hover{background:var(--panel-2)}
.table-footer{
    display:flex;
    justify-content:space-between;
    align-items:center;
    gap:12px;
    flex-wrap:wrap;
    padding:12px 16px;
    border-top:1px solid var(--border);
    color:var(--muted);
    font-size:12px;
}
.pagination{display:flex;align-items:center;gap:8px;flex-wrap:wrap}
.empty{
    padding:28px;
    text-align:center;
    color:var(--muted);
    border:1px dashed var(--border);
    border-radius:8px;
    background:var(--panel);
}
.footer{
    color:var(--muted);
    font-size:12px;
    padding:18px 0 8px;
    text-align:center;
}
.drawer-backdrop{
    display:none;
    position:fixed;
    inset:0;
    background:rgba(15,23,42,.45);
    z-index:25;
}
@media(max-width:1280px){
    .kpi-grid,.overview-grid,.quality-grid{grid-template-columns:repeat(2,minmax(0,1fr))}
    .profile-grid{grid-template-columns:repeat(2,minmax(0,1fr))}
}
@media(max-width:1060px){
    .app{grid-template-columns:1fr}
    .sidebar{
        position:fixed;
        left:0;
        top:0;
        width:min(86vw,var(--sidebar));
        transform:translateX(-105%);
        transition:transform .2s ease;
    }
    .sidebar.open{transform:translateX(0)}
    .drawer-backdrop.show{display:block}
    .menu-toggle{display:inline-flex}
    .charts-grid,.filter-grid{grid-template-columns:1fr}
}
@media(max-width:680px){
    .topbar{
        align-items:flex-start;
        flex-direction:column;
    }
    .topbar-left,.actions{width:100%}
    .actions{justify-content:stretch}
    .actions .btn{flex:1}
    .content{padding:16px}
    .kpi-grid,.overview-grid,.quality-grid,.profile-grid{grid-template-columns:1fr}
    .section-header{align-items:flex-start;flex-direction:column}
    .chart-card{min-height:380px}
    .chart{height:300px}
}
@media print{
    .sidebar,.topbar .actions,.menu-toggle,.drawer-backdrop,.filter-grid,.chart-actions,.table-footer{display:none!important}
    .app{display:block}
    .topbar{position:static;border-bottom:1px solid #ddd}
    .content{max-width:none;padding:12px}
    .card{box-shadow:none;break-inside:avoid}
    .kpi-grid,.overview-grid,.quality-grid,.profile-grid,.charts-grid{grid-template-columns:1fr 1fr}
}`;
}

