function createRuntimeScript() {
    return `
<script>
window.dashboardData = ${jsonForHtml(data)};

(function(){
    "use strict";

    var rawData = window.dashboardData || {};
    var state = {
        sourceRows: Array.isArray(rawData.rows) ? rawData.rows.slice() : [],
        filteredRows: [],
        columns: [],
        filters: {},
        filterColumns: [],
        search: "",
        sortColumn: null,
        sortDirection: "asc",
        page: 1,
        pageSize: 25,
        chartInstances: []
    };

    function byId(id){
        return document.getElementById(id);
    }

    function escapeHtml(value){
        if(value === null || value === undefined) return "";
        return String(value)
            .replace(/&/g,"&amp;")
            .replace(/</g,"&lt;")
            .replace(/>/g,"&gt;")
            .replace(/"/g,"&quot;")
            .replace(/'/g,"&#039;");
    }

    function text(value){
        if(value === null || value === undefined || value === "") return "—";
        if(Array.isArray(value)) return value.map(text).join(", ");
        if(typeof value === "object") return JSON.stringify(value);
        return String(value);
    }

    function titleCase(value){
        return String(value || "")
            .replace(/[_\\-]+/g," ")
            .replace(/\\s+/g," ")
            .trim()
            .replace(/\\w\\S*/g,function(part){
                return part.charAt(0).toUpperCase() + part.slice(1);
            });
    }

    function isMissing(value){
        return value === null || value === undefined || value === "";
    }

    function isNumberLike(value){
        if(isMissing(value)) return false;
        return Number.isFinite(Number(value));
    }

    function toNumber(value){
        if(value === null || value === undefined || value === "") return null;
        if(typeof value === "number") return Number.isFinite(value) ? value : null;

        var cleaned = String(value)
            .replace(/,/g,"")
            .replace(/[^\d.\-]/g,"");

        var number = Number(cleaned);
        return Number.isFinite(number) ? number : null;
    }

    function formatNumber(value, digits){
        if(value === null || value === undefined || value === "") return "—";
        var number = Number(value);
        if(!Number.isFinite(number)) return text(value);
        var abs = Math.abs(number);
        var maximumFractionDigits = digits !== undefined ? digits : (abs >= 100 ? 0 : 2);
        return new Intl.NumberFormat(undefined,{maximumFractionDigits:maximumFractionDigits}).format(number);
    }

    function formatValue(value){
        if(value === null || value === undefined || value === "") return "—";
        if(typeof value === "number") return formatNumber(value);
        if(typeof value === "boolean") return value ? "True" : "False";
        if(Array.isArray(value)) return value.map(formatValue).join(", ");
        if(typeof value === "object") return JSON.stringify(value);
        return String(value);
    }

    function readAny(object, keys, fallback){
        if(!object || typeof object !== "object") return fallback;
        for(var i=0;i<keys.length;i++){
            if(object[keys[i]] !== undefined && object[keys[i]] !== null && object[keys[i]] !== "") return object[keys[i]];
        }
        return fallback;
    }

    function getColumnName(column){
        if(typeof column === "string") return column;
        if(!column || typeof column !== "object") return "";
        return column.name || column.key || column.field || column.id || column.label || "";
    }

    function getColumnLabel(column, name){
        if(column && typeof column === "object") return column.label || column.title || column.display_name || column.displayName || titleCase(name);
        return titleCase(name);
    }

    function normalizeType(type){
        var value = String(type || "").toLowerCase();
        if(["integer","int","float","double","decimal","number","numeric","currency","percentage"].indexOf(value) !== -1) return "numeric";
        if(["date","datetime","timestamp","time"].indexOf(value) !== -1) return "date";
        if(["boolean","bool"].indexOf(value) !== -1) return "boolean";
        return value || "categorical";
    }

    function inferColumns(){
        var declared = Array.isArray(rawData.columns) ? rawData.columns : [];
        var names = [];

        declared.forEach(function(column){
            var name = getColumnName(column);
            if(name && names.indexOf(name) === -1) names.push(name);
        });

        state.sourceRows.forEach(function(row){
            if(!row || typeof row !== "object") return;
            Object.keys(row).forEach(function(key){
                if(names.indexOf(key) === -1) names.push(key);
            });
        });

        state.columns = names.map(function(name){
            var declaredColumn = declared.find(function(column){
                return getColumnName(column) === name;
            });
            var values = state.sourceRows.map(function(row){ return row ? row[name] : undefined; });
            var filled = values.filter(function(value){ return !isMissing(value); }).length;
            var numeric = values.filter(isNumberLike).length;
            var inferred = filled > 0 && numeric / filled >= .85 ? "numeric" : "categorical";
            var rawType = declaredColumn && typeof declaredColumn === "object" ? (declaredColumn.data_type || declaredColumn.dataType || declaredColumn.type || declaredColumn.semantic_type || declaredColumn.semanticType) : "";
            var finalType = rawType ? normalizeType(rawType) : inferred;
            if(finalType !== "numeric" && finalType !== "date" && finalType !== "boolean") finalType = "categorical";
            return {
                name:name,
                label:getColumnLabel(declaredColumn,name),
                type:finalType,
                raw:declaredColumn || {}
            };
        });
    }

    function valuesFor(columnName, rows){
        var source = rows || state.sourceRows;
        return source.map(function(row){ return row ? row[columnName] : undefined; });
    }

    function missingCount(values){
        return values.filter(isMissing).length;
    }

    function uniqueValues(values){
        var set = new Set();
        values.forEach(function(value){
            if(!isMissing(value)) set.add(String(value));
        });
        return Array.from(set);
    }

    function uniqueCount(values){
        return uniqueValues(values).length;
    }

    function percentile(sortedValues, p){
        if(!sortedValues.length) return null;
        var index = (sortedValues.length - 1) * p;
        var lower = Math.floor(index);
        var upper = Math.ceil(index);
        var weight = index - lower;
        if(upper >= sortedValues.length) return sortedValues[lower];
        return sortedValues[lower] * (1 - weight) + sortedValues[upper] * weight;
    }

    function numericStats(values){
        var nums = values.map(toNumber).filter(function(value){ return value !== null; }).sort(function(a,b){ return a-b; });
        if(!nums.length){
            return {count:0,min:null,max:null,average:null,median:null,stdDev:null,q1:null,q3:null,iqr:null};
        }
        var sum = nums.reduce(function(total,value){ return total + value; },0);
        var avg = sum / nums.length;
        var variance = nums.reduce(function(total,value){ return total + Math.pow(value - avg,2); },0) / nums.length;
        var q1 = percentile(nums,.25);
        var q3 = percentile(nums,.75);
        return {
            count:nums.length,
            min:nums[0],
            max:nums[nums.length - 1],
            average:avg,
            median:percentile(nums,.5),
            stdDev:Math.sqrt(variance),
            q1:q1,
            q3:q3,
            iqr:q3 !== null && q1 !== null ? q3 - q1 : null
        };
    }

    function metricCard(label,value,note,barPercent){
        var bar = typeof barPercent === "number" ? '<div class="quality-bar"><div class="quality-fill" style="width:' + Math.max(0,Math.min(100,barPercent)) + '%"></div></div>' : "";
        return '<article class="card card-pad metric-card"><div class="metric-label">' + escapeHtml(label) + '</div><div class="metric-value">' + escapeHtml(formatValue(value)) + '</div><div class="metric-note">' + escapeHtml(note || "") + '</div>' + bar + '</article>';
    }

    function getDashboardTitle(){
        return readAny(rawData.metadata,["title","name","dataset","dataset_name","datasetName","report_title","reportTitle"],"Business Intelligence Dashboard");
    }

    function getDashboardSubtitle(){
        return readAny(rawData.metadata,["description","subtitle","summary","source"],"Executive analytics and dataset intelligence");
    }

    function updateHeader(){
        byId("dashboardTitle").textContent = getDashboardTitle();
        byId("dashboardSubtitle").textContent = getDashboardSubtitle();
    }

    function cssEscape(value){
        if(window.CSS && typeof window.CSS.escape === "function") return window.CSS.escape(value);
        return String(value).replace(/["\\\\]/g,"\\\\$&");
    }

    function createFilters(){
        var grid = byId("filtersGrid");
        var sidebar = byId("sidebarFilters");

        state.filterColumns = state.columns.filter(function(column){
            if(column.type === "numeric") return false;
            var uniques = uniqueValues(valuesFor(column.name,state.sourceRows));
            return uniques.length > 0 && uniques.length <= 80;
        }).slice(0,6);

        var html = "";
        html += '<div class="control"><label for="globalSearch">Search</label><input class="input" id="globalSearch" type="search" placeholder="Search all rows"></div>';
        html += '<div class="control"><label for="pageSize">Rows per page</label><select class="select" id="pageSize"><option value="10">10 rows</option><option value="25" selected>25 rows</option><option value="50">50 rows</option><option value="100">100 rows</option></select></div>';

        state.filterColumns.slice(0,2).forEach(function(column){
            var values = uniqueValues(valuesFor(column.name,state.sourceRows)).sort();
            html += '<div class="control"><label for="filter_' + escapeHtml(column.name) + '">' + escapeHtml(column.label) + '</label><select class="select column-filter" id="filter_' + escapeHtml(column.name) + '" data-column="' + escapeHtml(column.name) + '"><option value="">All</option>' + values.map(function(value){ return '<option value="' + escapeHtml(value) + '">' + escapeHtml(value) + '</option>'; }).join("") + '</select></div>';
        });

        grid.innerHTML = html;

        sidebar.innerHTML = state.filterColumns.length ? state.filterColumns.map(function(column){
            var values = uniqueValues(valuesFor(column.name,state.sourceRows)).sort();
            return '<div class="sidebar-filter"><label for="side_filter_' + escapeHtml(column.name) + '">' + escapeHtml(column.label) + '</label><select class="side-column-filter" id="side_filter_' + escapeHtml(column.name) + '" data-column="' + escapeHtml(column.name) + '"><option value="">All</option>' + values.map(function(value){ return '<option value="' + escapeHtml(value) + '">' + escapeHtml(value) + '</option>'; }).join("") + '</select></div>';
        }).join("") : '<div class="sidebar-filter">No categorical filters available.</div>';

        byId("globalSearch").addEventListener("input",function(event){
            state.search = event.target.value || "";
            state.page = 1;
            refreshAll();
        });

        byId("pageSize").addEventListener("change",function(event){
            state.pageSize = Number(event.target.value) || 25;
            state.page = 1;
            renderTable();
        });

        Array.prototype.slice.call(document.querySelectorAll(".column-filter,.side-column-filter")).forEach(function(select){
            select.addEventListener("change",function(event){
                var column = event.target.getAttribute("data-column");
                var value = event.target.value;
                state.filters[column] = value;
                syncFilterControls(column,value);
                state.page = 1;
                refreshAll();
            });
        });
    }

    function syncFilterControls(column,value){
        Array.prototype.slice.call(document.querySelectorAll('[data-column="' + cssEscape(column) + '"]')).forEach(function(select){
            select.value = value;
        });
    }

    function resetFilters(){
        state.search = "";
        state.filters = {};
        state.page = 1;
        var search = byId("globalSearch");
        if(search) search.value = "";
        Array.prototype.slice.call(document.querySelectorAll(".column-filter,.side-column-filter")).forEach(function(select){
            select.value = "";
        });
        refreshAll();
    }

    function rowMatchesSearch(row){
        if(!state.search) return true;
        var query = String(state.search).toLowerCase();
        return Object.keys(row || {}).some(function(key){
            return String(row[key] === null || row[key] === undefined ? "" : row[key]).toLowerCase().indexOf(query) !== -1;
        });
    }

    function rowMatchesFilters(row){
        return Object.keys(state.filters).every(function(column){
            var expected = state.filters[column];
            if(!expected) return true;
            return String(row && !isMissing(row[column]) ? row[column] : "") === expected;
        });
    }

    function applyFilters(){
        state.filteredRows = state.sourceRows.filter(function(row){
            return rowMatchesSearch(row) && rowMatchesFilters(row);
        });
    }

    function calculateDuplicateRows(rows){
        var seen = new Set();
        var duplicates = 0;
        rows.forEach(function(row){
            var key = JSON.stringify(row);
            if(seen.has(key)) duplicates += 1;
            else seen.add(key);
        });
        return duplicates;
    }

    function calculateQualityScore(rows){
        var totalCells = Math.max(rows.length * Math.max(state.columns.length,1),1);
        var missing = state.columns.reduce(function(total,column){
            return total + missingCount(valuesFor(column.name,rows));
        },0);
        return Math.max(0,Math.min(100,(1 - missing / totalCells) * 100));
    }

    function countValue(value, fallback){
        if(Array.isArray(value)) return value.length;
        if(value && typeof value === "object") return Object.keys(value).length;
        if(value === null || value === undefined || value === "") return fallback;
        return value;
    }

    function renderOverview(){
        var metadata = rawData.metadata || {};
        var profiling = rawData.profiling || {};
        var rowCount = countValue(readAny(profiling,["rows","row_count","rowCount","totalRows"],state.sourceRows.length),state.sourceRows.length);
        var columnCount = countValue(readAny(profiling,["columns","column_count","columnCount","totalColumns"],state.columns.length),state.columns.length);
        var duplicateRows = readAny(profiling,["duplicate_rows","duplicateRows","duplicates"],calculateDuplicateRows(state.sourceRows));
        var quality = readAny(profiling,["data_quality","dataQuality","quality_score","qualityScore"],calculateQualityScore(state.sourceRows));
        var cards = [
            ["Dataset Type",readAny(metadata,["dataset_type","datasetType","type"],"Dataset"),"Metadata classification"],
            ["Business Domain",readAny(metadata,["business_domain","businessDomain","domain"],"General"),"Business context"],
            ["Description",readAny(metadata,["description","summary"],"No description supplied"),"Dataset purpose"],
            ["Rows",rowCount,"Total input rows"],
            ["Columns",columnCount,"Available fields"],
            ["Data Quality",typeof quality === "number" ? formatNumber(quality,1) + "%" : quality,"Overall quality score"],
            ["Duplicate Rows",duplicateRows,"Exact duplicate records"],
            ["Filtered Rows",state.filteredRows.length,"Rows after search and filters"]
        ];
        byId("overviewGrid").innerHTML = cards.map(function(card){
            return metricCard(card[0],card[1],card[2],String(card[0]).toLowerCase().indexOf("quality") !== -1 && typeof quality === "number" ? quality : undefined);
        }).join("");
    }

    function getKpiCharts(){
        return (Array.isArray(rawData.charts) ? rawData.charts : []).filter(function(chart){
            return chart && String(chart.type || chart.chartType || "").toLowerCase() === "kpi";
        });
    }

    function resolveKpiValue(chart){
        if(chart.value !== undefined) return chart.value;
        if(chart.metric_value !== undefined) return chart.metric_value;
        if(chart.metricValue !== undefined) return chart.metricValue;
        if(chart.data !== undefined && !Array.isArray(chart.data)) return chart.data;
        var column = chart.column || chart.field || chart.valueField || chart.y || chart.measure;
        var aggregation = String(chart.aggregation || chart.aggregate || "sum").toLowerCase();
        if(column){
            var values = valuesFor(column,state.filteredRows).map(toNumber).filter(function(value){ return value !== null; });
            if(!values.length) return "—";
            if(aggregation === "count") return values.length;
            if(aggregation === "avg" || aggregation === "average" || aggregation === "mean") return values.reduce(function(a,b){ return a+b; },0) / values.length;
            if(aggregation === "min") return Math.min.apply(null,values);
            if(aggregation === "max") return Math.max.apply(null,values);
            return values.reduce(function(a,b){ return a+b; },0);
        }
        return "—";
    }

    function renderKPIs(){
        var container = byId("kpiGrid");
        var kpis = getKpiCharts();

        if(!kpis.length){
            container.innerHTML = [
                {title:"Filtered Rows",value:state.filteredRows.length,note:"Rows currently visible"},
                {title:"Columns",value:state.columns.length,note:"Detected schema fields"},
                {title:"Quality Score",value:formatNumber(calculateQualityScore(state.filteredRows),1) + "%",note:"Completeness after filtering"},
                {title:"Charts",value:(Array.isArray(rawData.charts) ? rawData.charts : []).filter(function(chart){ return String(chart.type || chart.chartType || "").toLowerCase() !== "kpi"; }).length,note:"Interactive visuals"}
            ].map(function(kpi){
                return '<article class="card card-pad kpi-card"><div class="kpi-label">' + escapeHtml(kpi.title) + '</div><div class="kpi-value">' + escapeHtml(formatValue(kpi.value)) + '</div><div class="kpi-meta"><span>' + escapeHtml(kpi.note) + '</span></div></article>';
            }).join("");
            return;
        }

        container.innerHTML = kpis.map(function(chart){
            var label = chart.title || chart.label || chart.name || chart.metric || "KPI";
