            return '<article class="card card-pad kpi-card"><div class="kpi-label">' + escapeHtml(label) + '</div><div class="kpi-value">' + escapeHtml(formatValue(value)) + '</div><div class="kpi-meta"><span>' + escapeHtml(note) + '</span><strong class="' + changeClass + '">' + escapeHtml(change) + '</strong></div></article>';
        }).join("");
    }

    function renderQuality(){
        var totalCells = Math.max(state.filteredRows.length * Math.max(state.columns.length,1),1);
        var missing = state.columns.reduce(function(total,column){
            return total + missingCount(valuesFor(column.name,state.filteredRows));
        },0);
        var completeness = Math.max(0,Math.min(100,(1 - missing / totalCells) * 100));
        var duplicateRows = calculateDuplicateRows(state.filteredRows);
        var healthyColumns = state.columns.filter(function(column){
            var values = valuesFor(column.name,state.filteredRows);
            return !values.length || missingCount(values) / values.length <= .05;
        }).length;
        var cards = [
            ["Completeness",formatNumber(completeness,1) + "%","Non-missing cell percentage",completeness],
            ["Missing Values",missing,"Blank, null, and undefined cells"],
            ["Duplicate Rows",duplicateRows,"Exact duplicate rows in current view"],
            ["Healthy Columns",healthyColumns + " / " + state.columns.length,"Columns at least 95% complete"]
        ];
        byId("qualityGrid").innerHTML = cards.map(function(card){
            return metricCard(card[0],card[1],card[2],card[3]);
        }).join("");
    }

    function statFromRaw(raw, keys){
        return readAny(raw || {},keys,undefined);
    }

    function renderProfiling(){
        var container = byId("profileGrid");
        if(!state.columns.length){
            container.innerHTML = '<div class="empty">No columns were detected.</div>';
            return;
        }

        container.innerHTML = state.columns.map(function(column){
            var values = valuesFor(column.name,state.filteredRows);
            var raw = column.raw || {};
            var type = column.type === "numeric" ? "numeric" : "categorical";
            var statsHtml = "";

            if(type === "numeric"){
                var stats = numericStats(values);
                var items = [
                    ["Minimum",statFromRaw(raw,["minimum","min"]) !== undefined ? statFromRaw(raw,["minimum","min"]) : stats.min],
                    ["Maximum",statFromRaw(raw,["maximum","max"]) !== undefined ? statFromRaw(raw,["maximum","max"]) : stats.max],
                    ["Average",statFromRaw(raw,["average","avg","mean"]) !== undefined ? statFromRaw(raw,["average","avg","mean"]) : stats.average],
                    ["Median",statFromRaw(raw,["median"]) !== undefined ? statFromRaw(raw,["median"]) : stats.median],
                    ["Standard Deviation",statFromRaw(raw,["standard_deviation","standardDeviation","stdDev","std"]) !== undefined ? statFromRaw(raw,["standard_deviation","standardDeviation","stdDev","std"]) : stats.stdDev],
                    ["Q1",statFromRaw(raw,["q1","Q1"]) !== undefined ? statFromRaw(raw,["q1","Q1"]) : stats.q1],
                    ["Q3",statFromRaw(raw,["q3","Q3"]) !== undefined ? statFromRaw(raw,["q3","Q3"]) : stats.q3],
                    ["IQR",statFromRaw(raw,["iqr","IQR"]) !== undefined ? statFromRaw(raw,["iqr","IQR"]) : stats.iqr],
                    ["Missing Values",statFromRaw(raw,["missing_values","missingValues","missing"]) !== undefined ? statFromRaw(raw,["missing_values","missingValues","missing"]) : missingCount(values)]
                ];
                statsHtml = items.map(function(item){
                    return '<div class="stat"><div class="stat-label">' + escapeHtml(item[0]) + '</div><div class="stat-value">' + escapeHtml(formatNumber(item[1])) + '</div></div>';
                }).join("");
            } else {
                var categoricalItems = [
                    ["Unique Values",statFromRaw(raw,["unique_values","uniqueValues","unique"]) !== undefined ? statFromRaw(raw,["unique_values","uniqueValues","unique"]) : uniqueCount(values)],
                    ["Missing Values",statFromRaw(raw,["missing_values","missingValues","missing"]) !== undefined ? statFromRaw(raw,["missing_values","missingValues","missing"]) : missingCount(values)]
                ];
                statsHtml = categoricalItems.map(function(item){
                    return '<div class="stat"><div class="stat-label">' + escapeHtml(item[0]) + '</div><div class="stat-value">' + escapeHtml(formatValue(item[1])) + '</div></div>';
                }).join("");
            }

            return '<article class="card card-pad profile-card"><div class="profile-top"><div><div class="profile-name">' + escapeHtml(column.label) + '</div><div class="profile-sub">' + escapeHtml(column.name) + '</div></div><span class="badge">' + escapeHtml(type) + '</span></div><div class="profile-stats">' + statsHtml + '</div></article>';
        }).join("");
