    function chartType(chart){
        return String(chart.type || chart.chartType || "bar").toLowerCase();
    }

    function isSupportedChart(chart){
        return ["bar","line","pie","scatter","histogram"].indexOf(chartType(chart)) !== -1;
    }

    function nonKpiCharts(){
        return (Array.isArray(rawData.charts) ? rawData.charts : []).filter(function(chart){
            return chart && chartType(chart) !== "kpi" && isSupportedChart(chart);
        });
    }

    function fieldName(value){
        if(typeof value === "string") return value;
        if(!value || typeof value !== "object") return "";
        return value.field || value.name || value.column || value.key || value.id || value.label || "";
    }

    function getField(chart, keys){
        for(var i=0;i<keys.length;i++){
            if(chart[keys[i]]) return fieldName(chart[keys[i]]);
        }
        return "";
    }

    function normalizeKey(value){
        return String(value || "")
            .toLowerCase()
            .replace(/[^a-z0-9]/g,"");
    }

    function resolveColumnName(name){
        if(!name) return "";

        var wanted = normalizeKey(name);

        var exact = state.columns.find(function(column){
            return column.name === name || column.label === name;
        });
        if(exact) return exact.name;

        var normalized = state.columns.find(function(column){
            return normalizeKey(column.name) === wanted || normalizeKey(column.label) === wanted;
        });
        if(normalized) return normalized.name;

        var contains = state.columns.find(function(column){
            var columnKey = normalizeKey(column.name);
            var labelKey = normalizeKey(column.label);
            return columnKey.indexOf(wanted) !== -1 ||
                wanted.indexOf(columnKey) !== -1 ||
                labelKey.indexOf(wanted) !== -1 ||
                wanted.indexOf(labelKey) !== -1;
        });

        return contains ? contains.name : "";
    }

    function firstNumericColumn(exclude){
        var column = state.columns.find(function(item){
            return item.name !== exclude && item.type === "numeric";
        });
        return column ? column.name : "";
    }

    function firstCategoricalColumn(){
        var column = state.columns.find(function(item){
            return item.type !== "numeric";
        });
        return column ? column.name : "";
    }

    function aggregateRows(chart){
        var type = chartType(chart);
        var xField = resolveColumnName(getField(chart,["x","xField","x_axis","xAxis","labelField","category","categoryField","dimension"]));
        var yField = resolveColumnName(getField(chart,["y","yField","y_axis","yAxis","valueField","value","measure"]));
        var aggregation = String(chart.aggregation || chart.aggregate || "sum").toLowerCase();

        if(type === "pie"){
            var categoryField = xField || firstCategoricalColumn();
            if(!categoryField) return null;

            var counts = new Map();
            state.filteredRows.forEach(function(row){
                var key = text(row ? row[categoryField] : "");
                counts.set(key,(counts.get(key) || 0) + 1);
            });

            var pieLabels = Array.from(counts.keys());
            return {
                labels:pieLabels,
                values:pieLabels.map(function(label){ return counts.get(label); })
            };
        }

        if(type === "scatter"){
            var sx = xField || firstNumericColumn("");
            var sy = yField || firstNumericColumn(sx);
            if(!sx || !sy) return null;

            return {
                labels:[],
                values:state.filteredRows.map(function(row){
                    return [
                        toNumber(row ? row[sx] : null),
                        toNumber(row ? row[sy] : null)
                    ];
                }).filter(function(pair){
                    return pair[0] !== null && pair[1] !== null;
                })
            };
        }

        if(type === "histogram"){
            var hField = yField || xField || firstNumericColumn("");
            if(!hField) return null;

            return {labels:[],values:valuesFor(hField,state.filteredRows).map(toNumber).filter(function(value){ return value !== null; })};
        }

        if(xField && yField){
            var map = new Map();
            state.filteredRows.forEach(function(row){
                var key = text(row ? row[xField] : "");
                var numeric = toNumber(row ? row[yField] : null);
                var current = map.get(key) || {sum:0,count:0,min:null,max:null};
                if(numeric !== null){
                    current.sum += numeric;
                    current.count += 1;
                    current.min = current.min === null ? numeric : Math.min(current.min,numeric);
                    current.max = current.max === null ? numeric : Math.max(current.max,numeric);
                }
                map.set(key,current);
            });
            var labels = Array.from(map.keys());
            var values = labels.map(function(label){
                var item = map.get(label);
                if(aggregation === "count") return item.count;
                if(aggregation === "avg" || aggregation === "average" || aggregation === "mean") return item.count ? item.sum / item.count : 0;
                if(aggregation === "min") return item.min;
                if(aggregation === "max") return item.max;
                return item.sum;
            });
            return {labels:labels,values:values};
        }

        if(xField){
            var countMap = new Map();
            state.filteredRows.forEach(function(row){
                var key = text(row ? row[xField] : "");
                countMap.set(key,(countMap.get(key) || 0) + 1);
            });

            var countLabels = Array.from(countMap.keys());
            return {
                labels:countLabels,
                values:countLabels.map(function(label){ return countMap.get(label); })
            };
        }

        return null;
    }

    function extractChartData(chart){
        var aggregated = aggregateRows(chart);
        if(aggregated && aggregated.values && aggregated.values.length) return aggregated;

        var labels = chart.labels || chart.categories || chart.x_values || chart.xValues || [];
        var values = chart.values || chart.data || chart.series || chart.y_values || chart.yValues || [];

        if(values && !Array.isArray(values) && typeof values === "object" && Array.isArray(values.data)) values = values.data;
        if(!Array.isArray(values) && fieldName(values)) values = valuesFor(fieldName(values),state.filteredRows);
        if(!Array.isArray(labels) && fieldName(labels)) labels = valuesFor(fieldName(labels),state.filteredRows);
        if(labels && !Array.isArray(labels)) labels = [];

        if(Array.isArray(values) && values.length && typeof values[0] === "object" && !Array.isArray(values[0])){
            if(!labels.length){
                labels = values.map(function(item){
                    return item.name || item.label || item.category || item.x || "";
                });
            }
            values = values.map(function(item){
                if(chartType(chart) === "scatter") return [toNumber(item.x) || 0,toNumber(item.y) || 0];
                return item.value !== undefined ? item.value : item.y !== undefined ? item.y : item.count !== undefined ? item.count : item.total;
            });
        }

        if(!Array.isArray(values)) values = [];
        if(!Array.isArray(labels)) labels = [];

        return {labels:labels,values:values};
    }

    function histogramBins(values, binCount){
        var nums = values.map(toNumber).filter(function(value){ return value !== null; }).sort(function(a,b){ return a-b; });
        if(!nums.length) return {labels:[],values:[]};
        var min = nums[0];
        var max = nums[nums.length - 1];
        var bins = Math.max(3,binCount || Math.ceil(Math.sqrt(nums.length)));
        if(min === max) return {labels:[String(min)],values:[nums.length]};
        var width = (max - min) / bins;
        var counts = Array.from({length:bins},function(){ return 0; });
        nums.forEach(function(value){
            var index = Math.min(Math.floor((value - min) / width),bins - 1);
            counts[index] += 1;
        });
        return {
            labels:counts.map(function(_,index){
                var start = min + index * width;
                var end = start + width;
                return formatNumber(start) + " - " + formatNumber(end);
            }),
            values:counts
        };
    }

    function createChartOption(chart){
        var type = chartType(chart);
        var extracted = extractChartData(chart);
        var labels = extracted.labels.slice();
        var values = extracted.values.slice();
        var title = chart.title || chart.name || chart.label || titleCase(type) + " Chart";
        var palette = ["#2563eb","#00a3a3","#742774","#f2c811","#16a34a","#dc2626","#0891b2","#db2777"];

        var option = {
            color:palette,
            animation:true,
            animationDuration:900,
            textStyle:{fontFamily:"Inter, Segoe UI, Arial, sans-serif"},
            tooltip:{trigger:type === "pie" ? "item" : "axis",axisPointer:{type:"shadow"}},
            legend:{top:6,type:"scroll"},
            toolbox:{
                right:12,
                feature:{
                    dataZoom:{yAxisIndex:"none"},
                    restore:{},
                    saveAsImage:{title:"Save As Image",pixelRatio:2}
                }
            },
            grid:{top:58,right:24,bottom:58,left:54,containLabel:true}
        };

        if(type === "pie"){
            option.tooltip = {trigger:"item"};
            option.series = [{
                name:title,
                type:"pie",
                radius:["42%","72%"],
                center:["50%","55%"],
                avoidLabelOverlap:true,
                itemStyle:{borderRadius:6,borderColor:"#fff",borderWidth:2},
                data:values.map(function(value,index){
                    return {name:labels[index] || "Item " + (index + 1),value:value};
                })
            }];
            return option;
        }

        if(type === "scatter"){
            option.xAxis = {type:"value",splitLine:{lineStyle:{type:"dashed"}}};
            option.yAxis = {type:"value",splitLine:{lineStyle:{type:"dashed"}}};
            option.dataZoom = [{type:"inside"},{type:"slider",height:22,bottom:16}];
            option.series = [{
                name:title,
                type:"scatter",
                symbolSize:10,
                data:values.map(function(value,index){
                    if(Array.isArray(value)) return value;
                    return [index + 1,toNumber(value) || 0];
                })
            }];
            return option;
        }

        if(type === "histogram"){
            var histogram = histogramBins(values,chart.bins || chart.binCount);
            labels = histogram.labels;
            values = histogram.values;
            type = "bar";
        }

        option.xAxis = {type:"category",data:labels.length ? labels : values.map(function(_,index){ return "Item " + (index + 1); }),axisLabel:{hideOverlap:true}};
        option.yAxis = {type:"value",splitLine:{lineStyle:{type:"dashed"}}};
        option.dataZoom = [{type:"inside"},{type:"slider",height:22,bottom:16}];
        option.series = [{
            name:title,
            type:type === "line" ? "line" : "bar",
            smooth:type === "line",
            areaStyle:type === "line" && chart.area ? {} : undefined,
            barMaxWidth:52,
            data:values
        }];
        return option;
    }

    function renderCharts(){
        var container = byId("chartsGrid");
        var charts = nonKpiCharts();

        state.chartInstances.forEach(function(instance){
            if(instance && instance.dispose) instance.dispose();
        });
        state.chartInstances = [];

        if(!charts.length){
            container.innerHTML = '<div class="empty">No non-KPI chart definitions were supplied.</div>';
            return;
        }

        container.innerHTML = charts.map(function(chart,index){
            var title = chart.title || chart.name || chart.label || "Chart " + (index + 1);
            var subtitle = chart.description || chart.subtitle || titleCase(chartType(chart));
            return '<article class="card chart-card"><div class="chart-header"><div><h3 class="chart-title">' + escapeHtml(title) + '</h3><div class="chart-subtitle">' + escapeHtml(subtitle) + '</div></div><div class="chart-actions"><button class="icon-btn" type="button" data-download-chart="' + index + '" aria-label="Download chart"><svg class="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><path d="M7 10l5 5 5-5"/><path d="M12 15V3"/></svg></button></div></div><div class="chart" id="chart_' + index + '"></div></article>';
        }).join("");

        charts.forEach(function(chart,index){
            var el = byId("chart_" + index);
            if(!el || !window.echarts) return;
            var instance = echarts.init(el,null,{renderer:"canvas"});
            instance.setOption(createChartOption(chart),true);
            state.chartInstances[index] = instance;
        });

        Array.prototype.slice.call(document.querySelectorAll("[data-download-chart]")).forEach(function(button){
            button.addEventListener("click",function(){
                var index = Number(button.getAttribute("data-download-chart"));
                var instance = state.chartInstances[index];
                if(!instance) return;
                var url = instance.getDataURL({type:"png",pixelRatio:2,backgroundColor:"#ffffff"});
                var link = document.createElement("a");
                link.href = url;
                link.download = "chart-" + (index + 1) + ".png";
                link.click();
            });
        });
    }

    function compareRows(a,b){
        var av = a && state.sortColumn ? a[state.sortColumn] : "";
        var bv = b && state.sortColumn ? b[state.sortColumn] : "";
        var an = toNumber(av);
        var bn = toNumber(bv);
        if(an !== null && bn !== null) return an - bn;
        return String(av === null || av === undefined ? "" : av).localeCompare(String(bv === null || bv === undefined ? "" : bv),undefined,{numeric:true,sensitivity:"base"});
    }

    function renderTable(){
        var card = byId("tableCard");
        if(!state.columns.length){
            card.innerHTML = '<div class="empty">No table columns were detected.</div>';
            return;
        }

        var rows = state.filteredRows.slice();
        if(state.sortColumn){
            rows.sort(compareRows);
            if(state.sortDirection === "desc") rows.reverse();
        }

        var totalPages = Math.max(1,Math.ceil(rows.length / state.pageSize));
        state.page = Math.min(Math.max(1,state.page),totalPages);
        var start = (state.page - 1) * state.pageSize;
        var pageRows = rows.slice(start,start + state.pageSize);

        var head = state.columns.map(function(column){
            var marker = state.sortColumn === column.name ? (state.sortDirection === "asc" ? " ▲" : " ▼") : "";
            return '<th class="sortable" data-sort="' + escapeHtml(column.name) + '">' + escapeHtml(column.label + marker) + '</th>';
        }).join("");

        var body = pageRows.length ? pageRows.map(function(row){
            return '<tr>' + state.columns.map(function(column){
                var value = formatValue(row ? row[column.name] : "");
                return '<td title="' + escapeHtml(value) + '">' + escapeHtml(value) + '</td>';
            }).join("") + '</tr>';
        }).join("") : '<tr><td colspan="' + state.columns.length + '">No rows match the current search and filters.</td></tr>';

        card.innerHTML = '<div class="table-shell"><table><thead><tr>' + head + '</tr></thead><tbody>' + body + '</tbody></table></div><div class="table-footer"><div>Showing ' + escapeHtml(rows.length ? start + 1 : 0) + '–' + escapeHtml(Math.min(start + state.pageSize,rows.length)) + ' of ' + escapeHtml(rows.length) + ' rows</div><div class="pagination"><button class="btn" id="prevPage" type="button">Previous</button><span>Page ' + escapeHtml(state.page) + ' of ' + escapeHtml(totalPages) + '</span><button class="btn" id="nextPage" type="button">Next</button></div></div>';

        Array.prototype.slice.call(card.querySelectorAll("[data-sort]")).forEach(function(th){
            th.addEventListener("click",function(){
                var column = th.getAttribute("data-sort");
                if(state.sortColumn === column){
                    state.sortDirection = state.sortDirection === "asc" ? "desc" : "asc";
                } else {
                    state.sortColumn = column;
                    state.sortDirection = "asc";
                }
                renderTable();
            });
        });

        byId("prevPage").addEventListener("click",function(){
            state.page = Math.max(1,state.page - 1);
            renderTable();
        });

        byId("nextPage").addEventListener("click",function(){
            state.page = Math.min(totalPages,state.page + 1);
            renderTable();
        });
    }

    function createFooter(){
        var metadata = rawData.metadata || {};
        var source = readAny(metadata,["source","file","dataset","dataset_name"],"dynamic n8n input");
        byId("footer").textContent = "Generated from " + source + " • " + new Date().toLocaleString();
    }

    function refreshAll(){
        applyFilters();
        renderOverview();
        renderKPIs();
        renderQuality();
        renderProfiling();
        renderCharts();
        renderTable();
    }

    function bindActions(){
        byId("resetFilters").addEventListener("click",resetFilters);
        byId("printDashboard").addEventListener("click",function(){ window.print(); });

        byId("exportDashboard").addEventListener("click",function(){
            var instance = state.chartInstances.find(function(chart){ return !!chart; });
            if(!instance){
                window.print();
                return;
            }
            var url = instance.getDataURL({type:"png",pixelRatio:2,backgroundColor:"#ffffff"});
            var link = document.createElement("a");
            link.href = url;
            link.download = "dashboard-export.png";
            link.click();
        });

        byId("menuToggle").addEventListener("click",function(){
            byId("sidebar").classList.add("open");
            byId("drawerBackdrop").classList.add("show");
        });

        byId("drawerBackdrop").addEventListener("click",function(){
            byId("sidebar").classList.remove("open");
            byId("drawerBackdrop").classList.remove("show");
        });

        Array.prototype.slice.call(document.querySelectorAll(".nav-link[href]")).forEach(function(link){
            link.addEventListener("click",function(){
                byId("sidebar").classList.remove("open");
                byId("drawerBackdrop").classList.remove("show");
                Array.prototype.slice.call(document.querySelectorAll(".nav-link")).forEach(function(item){ item.classList.remove("active"); });
                link.classList.add("active");
            });
        });

        window.addEventListener("resize",function(){
            state.chartInstances.forEach(function(instance){
                if(instance) instance.resize();
            });
        });
    }

    function renderDashboard(){
        inferColumns();
        state.filteredRows = state.sourceRows.slice();
        updateHeader();
        createFilters();
        refreshAll();
        createFooter();
        bindActions();
    }

    if(document.readyState === "loading"){
        document.addEventListener("DOMContentLoaded",renderDashboard);
    } else {
        renderDashboard();
    }
})();
</script>`;
}

function buildDashboard() {
    return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>Business Intelligence Dashboard</title>
<script src="https://cdn.jsdelivr.net/npm/echarts@5/dist/echarts.min.js"></script>
<style>
${createCSS()}
</style>
</head>
<body>
${createDashboardShell()}
${createRuntimeScript()}
</body>
</html>`;
}

const html = buildDashboard();

return [{
    json:{
        html
    }
}];

const data = $input.first().json;

return [{
  json: {
    metadata: data.metadata,

    columns: data.metadata.columns,

    totalRows: data.data.length,

    totalColumns: data.metadata.columns.length,

    sampleRows: data.data.slice(0, 5)
  }
}];

const items = $input.all();

let profiling = {};
let chartUrls = [];
const sampleRows = [];

for (const item of items) {
  const json = item.json;

  if (json.profiling) {
    profiling = json.profiling;
  }

  if (json.chartUrls) {
    chartUrls = Array.isArray(json.chartUrls) ? json.chartUrls : [json.chartUrls];
  }

  if (json.charts) {
    chartUrls = Array.isArray(json.charts) ? json.charts : [json.charts];
  }

  if (json.quickChartUrls) {
    chartUrls = Array.isArray(json.quickChartUrls) ? json.quickChartUrls : [json.quickChartUrls];
  }

  const isControlItem =
    json.profiling ||
    json.chartUrls ||
    json.charts ||
    json.quickChartUrls;

  if (!isControlItem && sampleRows.length < 5) {
    sampleRows.push(json);
  }
}

return [{
  json: {
    profiling,
    chartUrls,
    sampleRows: sampleRows.slice(0, 5)
  }
}];
